  ('dietitian-moex-07094', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關血清中電解質的正常值，下列何者正確？ 鈉3～4.5 mg/dL  鉀3.5～5 mEq/L  鈣3.5～5 mg/dL  磷8.5～10.5 mEq/L', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "73db2979bfee", "answer_pdf_sha1": "152727bd9506", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07095', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '以下有關「營養篩檢」之敘述何者正確？ 不是營養治療的一部分 相等於營養評估，只是步驟簡單些 目的是快速將高營養風險者找出來，進一步做營養評估 只能由營養師執行，其他醫療人員不可擔任', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "73db2979bfee", "answer_pdf_sha1": "152727bd9506", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07096', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何種疾病病患，治療中最容易因為腸道吸收不良產生食物與藥物之交互作用？ 糖尿病患  精神病患  癌症病患  肥胖病患', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "73db2979bfee", "answer_pdf_sha1": "152727bd9506", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07097', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '服用皮質類固醇（corticosteroids）藥物所引起的高血糖是因下列何種原因？ 藥物促進糖解作用（glycolysis）  藥物降低胰島素阻抗 藥物減少胰島素分泌    藥物促進糖質新生作用（gluconeogenesis）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "73db2979bfee", "answer_pdf_sha1": "152727bd9506", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07098', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何者不是選擇管灌食插管方式的考慮因素？ 需要使用管灌食的時間長短  患者是否能插管 患者發生肺吸入（aspiration）的危險性  患者的營養需要', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "73db2979bfee", "answer_pdf_sha1": "152727bd9506", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07099', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '許多藥物不可與葡萄柚汁一起服用，是因葡萄柚汁會抑制下列何種酵素的活性？ 胰脂解酶    HMG-CoA 還原酶 細胞色素P-450 3A4酵素  α -糖苷酶', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "73db2979bfee", "answer_pdf_sha1": "152727bd9506", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
